using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer()
    .WithHttpTransport()
    .WithTools<MyTools>()
    .WithResources<ConfigResources>();

var app = builder.Build();

app.MapMcp();

app.Run();

// --- Tools ---

[McpServerToolType]
public static class MyTools
{
    [McpServerTool(Name = "echo"), System.ComponentModel.Description("Echoes back the input message.")]
    public static string Echo(string message) => $"Echo: {message}";

    [McpServerTool(Name = "add"), System.ComponentModel.Description("Adds two numbers.")]
    public static double Add(double a, double b) => a + b;
}

// --- Resources ---

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "app-settings",
        Description = "Returns application configuration data.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = "Development",
            Features = new { EnableLogging = true, MaxRetries = 3 }
        };
        return System.Text.Json.JsonSerializer.Serialize(config, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/status", Name = "app-status",
        Description = "Returns current server status.")]
    public static string GetStatus() =>
        System.Text.Json.JsonSerializer.Serialize(new { Status = "Healthy", Uptime = Environment.TickCount64 / 1000 });
}

