2. using ModelContextProtocol.Server;
3. 
4. var builder = WebApplication.CreateBuilder(args);
5. 
6. builder.Services
7.     .AddMcpServer()
8.     .WithHttpTransport()
9.     .WithTools<MyTools>()
10.     .WithResources<ConfigResources>();
11. 
12. var app = builder.Build();
13. 
14. app.MapMcp("/mcp");
15. 
16. app.Run();
