20. [McpServerToolType]
21. public sealed class MyTools
22. {
23.     [McpServerTool(Name = "echo"), Description("Echoes back the input message.")]
24.     public static string Echo(string message) => $"Echo: {message}";
25. 
26.     [McpServerTool(Name = "add"), Description("Adds two numbers.")]
27.     public static double Add(double a, double b) => a + b;
28. }
29. 
