31. 
32. [McpServerResourceType]
33. public sealed class ConfigResources
34. {
35.     [McpServerResource(UriTemplate = "config://app/settings", Name = "app-settings", MimeType = "application/json")]
36.     [Description("Returns application configuration data.")]
37.     public static string GetAppSettings()
38.     {
39.         var config = new
40.         {
41.             AppName = "McpHttpServer",
42.             Version = "1.0.0",
43.             Environment = "Development",
44.             Features = new { EnableLogging = true, MaxRetries = 3 }
45.         };
46.         return System.Text.Json.JsonSerializer.Serialize(config, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
47.     }
48. 
49.     [McpServerResource(UriTemplate = "config://app/status", Name = "app-status", MimeType = "application/json")]
50.     [Description("Returns current server status.")]
51.     public static string GetStatus() =>
52.         System.Text.Json.JsonSerializer.Serialize(new { Status = "Healthy", Uptime = Environment.TickCount64 / 1000 });
53. }
54.

